(function(w){"use strict";const ID="date-diff";function parse(v){const [y,m,d]=String(v).split("-").map(Number);const dt=new Date(y,m-1,d);return Number.isFinite(y)&&dt.getFullYear()===y&&dt.getMonth()===m-1&&dt.getDate()===d?dt:null}function compute(x){const a=parse(x.start),b=parse(x.end);if(!a||!b)return{error:"두 날짜를 올바르게 선택해 주세요."};const days=Math.round((Date.UTC(b.getFullYear(),b.getMonth(),b.getDate())-Date.UTC(a.getFullYear(),a.getMonth(),a.getDate()))/86400000);return{days,absolute:Math.abs(days),inclusive:Math.abs(days)+1}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>시작일</label><input type="date" class="hm-calc-input"></div><div class="hm-calc-field"><label>종료일</label><input type="date" class="hm-calc-input"></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">날짜 차이 계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const [a,b]=root.querySelectorAll("input"),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");a.value=b.value=api.localDateString();go.addEventListener("click",()=>{const r=compute({start:a.value,end:b.value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("두 날짜의 차이",`${api.formatNumber(r.absolute,0)}일`,`<dl><dt>양 끝 날짜 포함</dt><dd>${api.formatNumber(r.inclusive,0)}일</dd><dt>방향 포함 차이</dt><dd>${api.formatNumber(r.days,0)}일</dd></dl>`));});}w.HM_CALC.register(ID,{compute,render});})(window);
